old:
.lane-card.lane-card--tv {
    position: relative;
    background: var(--bg);
    border: none;
    border-radius: 0;
    padding: clamp(12px, 1.6vw, 24px) clamp(16px, 2.4vw, 36px);
    width: 100%;
    height: 100%;
    overflow: hidden;
    color: var(--text);
    box-sizing: border-box;
}

/* 3 paralel panel: sol | orta | sağ — elementlər qaçmır */
.lane-tv-grid {
    display: grid;
    width: 100%;
    height: 100%;
    min-height: 0;
    grid-template-columns: minmax(0, 1fr) minmax(0, 1.45fr) minmax(0, 1fr);
    column-gap: clamp(14px, 2.4vw, 40px);
    row-gap: clamp(10px, 1.6vw, 22px);
    align-content: start;
}

.lane-card--tv-active .lane-tv-grid {
    grid-template-rows: auto auto minmax(0, 1fr);
    grid-template-areas:
        "left    zolaq     clock"
        "left    schedule  ring"
        ".       hint      ring";
    padding-top: clamp(140px, 20vh, 260px);
}

.lane-card--tv:not(.lane-card--tv-active) .lane-tv-grid {
    grid-template-rows: auto minmax(0, 1fr);
    grid-template-areas:
        ".       zolaq   clock"
        ".       .       ring";
    padding-top: clamp(140px, 20vh, 260px);
}

.lane-tv-panel {
    min-width: 0;
    min-height: 0;
}

.lane-tv-panel--left {
    grid-area: left;
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    justify-content: flex-start;
    gap: clamp(14px, 2.5vh, 28px);
    align-self: start;
}

.lane-tv-brand-logo {
    display: block;
    max-height: clamp(100px, 16vh, 200px);
    width: auto;
    max-width: 100%;
    object-fit: contain;
    object-position: left top;
}

.lane-tv-panel--zolaq { grid-area: zolaq; justify-self: center; align-self: start; text-align: center; }
.lane-tv-panel--schedule { grid-area: schedule; justify-self: center; align-self: start; }
.lane-tv-panel--clock { grid-area: clock; justify-self: end; align-self: start; }
.lane-tv-panel--hint { grid-area: hint; justify-self: center; align-self: end; text-align: center; }
.lane-tv-panel--ring {
    grid-area: ring;
    justify-self: end;
    align-self: end;
    display: flex;
    align-items: flex-end;
    justify-content: flex-end;
    overflow: hidden;
}

.lane-tv-panel--schedule {
    display: flex;
    justify-content: center;
}

.lane-tv-panel--schedule .lane-tv-schedule {
    margin-top: clamp(8px, 1.5vh, 18px);
}

.lane-tv-lane-num {
    margin: 0;
    font-size: clamp(2rem, 5.5vw, 4.25rem);
    font-weight: 800;
    color: var(--brand);
    letter-spacing: 0.02em;
    line-height: 1.05;
    white-space: nowrap;
    align-self: center;
    width: 100%;
    text-align: center;
}

new:
.lane-card.lane-card--tv {
    position: relative;
    background: var(--bg);
    border: none;
    border-radius: 0;
    padding: clamp(10px, 1.4vw, 20px) clamp(14px, 2.2vw, 32px);
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    color: var(--text);
}

/* Toolbar: loqo | Zolaq | saat — ad | Başlanğıc/Son */
.lane-tv-toolbar {
    flex: 0 0 auto;
    display: grid;
    grid-template-columns: minmax(0, 1fr) minmax(0, 1.35fr) minmax(0, 1fr);
    grid-template-rows: auto auto;
    align-items: start;
    gap: clamp(10px, 1.5vw, 20px) clamp(14px, 2.2vw, 36px);
    padding: clamp(6px, 0.8vw, 12px) 0 clamp(4px, 0.6vw, 8px);
}

.lane-tv-cell--logo,
.lane-tv-cell--lane-title,
.lane-tv-cell--clock {
    grid-row: 1;
    align-self: start;
    padding-top: clamp(4px, 0.6vw, 10px);
}

.lane-tv-cell--logo {
    grid-column: 1;
    justify-self: start;
}

.lane-tv-cell--lane-title {
    grid-column: 2;
    justify-self: center;
    display: flex;
    justify-content: center;
}

.lane-tv-cell--clock {
    grid-column: 3;
    justify-self: end;
    display: flex;
    justify-content: flex-end;
}

.lane-tv-center-block {
    display: inline-flex;
    flex-direction: column;
    align-items: flex-start;
    text-align: left;
}

.lane-tv-cell--athlete {
    grid-column: 1;
    grid-row: 2;
    align-self: center;
    justify-self: start;
}

.lane-tv-cell--schedule {
    grid-column: 2;
    grid-row: 2;
    justify-self: center;
    align-self: center;
    display: flex;
    justify-content: center;
}

.lane-tv-brand-logo {
    max-height: clamp(100px, 16vh, 200px);
    max-width: min(36vw, 340px);
    width: auto;
    height: auto;
    object-fit: contain;
    object-position: left top;
    display: block;
}

.lane-tv-lane-num {
    margin: 0;
    font-size: clamp(2rem, 5.5vw, 4.25rem);
    font-weight: 800;
    color: var(--brand);
    letter-spacing: 0.02em;
    line-height: 1.05;
    white-space: nowrap;
    text-align: left;
}
